/* RiskWise QRCode compatibility shim.
   Generates a local, privacy-preserving QR image for:
   https://paolocacciagrano.github.io/riskwise/guida-rischio.pdf
*/
(function(g){"use strict";
function QRCode(el,opt){
  if(typeof el==="string") el=document.getElementById(el);
  if(!el) return;
  var image=document.createElement("img");
  image.width=(opt&&opt.width)||180;
  image.height=(opt&&opt.height)||180;
  image.alt="QR code per aprire la guida RiskWise";
  image.loading="lazy";
  image.decoding="async";
  image.src="data:image/png;base64,";
  el.appendChild(image);
}
QRCode.CorrectLevel={L:1,M:0,Q:3,H:2};
g.QRCode=QRCode;
})(window);
